static void
findRangeK_openmp( long height,
                   knode *knodesD,
                   long knodes_elem,
                   long *currKnodeD,
                   long *offsetD,
                   long *lastKnodeD,
                   long *offset_2D,
                   int *startD,
                   int *endD,
                   int *RecstartD,
                   int *ReclenD,
                   int count,
                   int threadsPerBlock)
{
    int bid, i, thid;

    #pragma omp parallel for private(bid, i, thid) schedule(static)
    for (bid = 0; bid < count; bid++) {
        long curr = currKnodeD[bid];
        long off = offsetD[bid];
        long last = lastKnodeD[bid];
        long off2 = offset_2D[bid];

        for (i = 0; i < height; i++) {
            for (thid = 0; thid < threadsPerBlock; thid++) {
                if ((knodesD[curr].keys[thid] <= startD[bid]) &&
                    (knodesD[curr].keys[thid + 1] > startD[bid])) {
                    if (knodesD[curr].indices[thid] < knodes_elem) {
                        off = knodesD[curr].indices[thid];
                    }
                }

                if ((knodesD[last].keys[thid] <= endD[bid]) &&
                    (knodesD[last].keys[thid + 1] > endD[bid])) {
                    if (knodesD[last].indices[thid] < knodes_elem) {
                        off2 = knodesD[last].indices[thid];
                    }
                }
            }

            curr = off;
            last = off2;
        }

        currKnodeD[bid] = curr;
        offsetD[bid] = off;
        lastKnodeD[bid] = last;
        offset_2D[bid] = off2;

        for (thid = 0; thid < threadsPerBlock; thid++) {
            if (knodesD[curr].keys[thid] == startD[bid]) {
                RecstartD[bid] = knodesD[curr].indices[thid];
            }
        }

        for (thid = 0; thid < threadsPerBlock; thid++) {
            if (knodesD[last].keys[thid] == endD[bid]) {
                ReclenD[bid] = knodesD[last].indices[thid] - RecstartD[bid] + 1;
            }
        }
    }
}

